	// 获取登录用户是否具备管理员权限
	IsExistAdminRightUser(context.Context, *EmptyRequest) (*IsExistAdminRightUserResponse, error)
	// 获取卸载软件任务状态
	GetUninstallSoftwareTaskInfo(context.Context, *GetUninstallTaskInfoRequest) (*GetUninstallTaskInfoResponse, error)
	// 释放卸载软件信息
	ClearUninstallSoftwareTaskInfo(context.Context, *ClearUninstallSoftwareTaskInfoRequest) (*CodeResponse, error)
	// 获取应用信息
	GetAppInfo(context.Context, *EmptyRequest) (*AppInfoResponse, error)
	// 检测是否展示 Wi-Fi 引导，返回0则展示，非0不展示
	CheckWiFiGuide(context.Context, *CheckWiFiGuideRequest) (*WiFiGuideResponse, error)
	// 忘记 Wi-Fi
	RemoveWiFi(context.Context, *WiFiRemoveRequest) (*CodeResponse, error)
	// 获取系统代理状态
