	// 配置云打印机
	ConfigCloudPrinter(context.Context, *EmptyRequest) (*CodeResponse, error)
	// 上传打印文件
	CloudPrinterUpload(context.Context, *CloudPrintUploadRequest) (*CodeResponse, error)
	// 获取有线状态
	GetWiredStatus(context.Context, *EmptyRequest) (*WiredStatusResponse, error)
	// 字节内部专属服务 -- End
	// 获取补丁状态
	CheckPatchStatus(context.Context, *EmptyRequest) (*PatchStatusResponse, error)
	// 强制刷新配置
	RefreshConfig(context.Context, *EmptyRequest) (*CodeResponse, error)
	// 远程控制相关API
	// 创建新密码
	RemoteControlNewPassword(context.Context, *EmptyRequest) (*RemoteControlNewPasswordResponse, error)
	// 用户对远程控制请求的决策 同意，拒绝，超时，验证码不对
	RemoteControlResult(context.Context, *RemoteControlResult) (*CodeResponse, error)
	// 获得远程控制结果
	RemoteControlQuery(context.Context, *RemoteControlQueryInfo) (*RemoteControlQueryResponse, error)
	// 用户离开远程协助页面
	RemoteControlDestory(context.Context, *EmptyRequest) (*CodeResponse, error)
	RemoteControlGetVerifyInfo(context.Context, *RemoteControlVerifyInfoRequest) (*RemoteControlVerifyInfoResponse, error)
	RemoteControlCancel(context.Context, *RemoteControlCancelRequest) (*CodeResponse, error)
